 13	} from '@patternfly/react-core';
 14	import { FilterIcon, TimesIcon } from '@patternfly/react-icons';
 15	import { BaseEdge, BaseNode } from '@patternfly/react-topology';
 16	import * as React from 'react';
 17	import { useTranslation } from 'react-i18next';
 18	import { Filter, FilterDefinition, Filters } from '../../../model/filters';
 19	import { GraphElementPeer, isElementFiltered, NodeData, toggleElementFilter } from '../../../model/topology';
 20	import { createPeer } from '../../../utils/metrics';
 21	import { ElementFields } from './element-fields';
 22	
 23	export interface ElementPanelContentProps {
 24	  element: GraphElementPeer;
 25	  filters: Filters;
 26	  setFilters: (filters: Filter[]) => void;
 27	  filterDefinitions: FilterDefinition[];
 28	}
 29	
 30	export const ElementPanelContent: React.FC<ElementPanelContentProps> = ({
 31	  element,
 32	  filters,
 33	  setFilters,
 34	  filterDefinitions
 35	}) => {
 36	  const { t } = useTranslation('plugin__netobserv-plugin');
 37	  const [hidden, setHidden] = React.useState<string[]>([]);
 38	  const data = element.getData();
 39	
 40	  const toggle = React.useCallback(
 41	    (id: string) => {
 42	      const index = hidden.indexOf(id);
 43	      const newExpanded: string[] =
 44	        index >= 0 ? [...hidden.slice(0, index), ...hidden.slice(index + 1, hidden.length)] : [...hidden, id];
 45	      setHidden(newExpanded);
 46	    },
 47	    [hidden]
 48	  );
 49	
 50	  const clusterName = React.useCallback(
 51	    (d: NodeData) => {
 52	      if (!d.peer.cluster) {
 53	        return <></>;
 54	      }
 55	      const fields = createPeer({ cluster: d.peer.cluster });
 56	      const isFiltered = isElementFiltered(fields, filters.list, filterDefinitions);
 57	      return (
 58	        <TextContent id="clusterName" className="record-field-container">
 59	          <Text component={TextVariants.h4}>{t('Cluster name')}</Text>
 60	          <Flex>
 61	            <FlexItem flex={{ default: 'flex_1' }}>{d.peer.cluster}</FlexItem>
 62	            <FlexItem>
 63	              <Button
 64	                id={'clustername-filter'}
 65	                variant="plain"
 66	                className="overflow-button"
 67	                icon={isFiltered ? <TimesIcon /> : <FilterIcon />}
 68	                onClick={() => toggleElementFilter(fields, isFiltered, filters.list, setFilters, filterDefinitions)}
 69	              />
 70	            </FlexItem>
 71	          </Flex>
 72	        </TextContent>
 73	      );
 74	    },
 75	    [filterDefinitions, filters, setFilters, t]
 76	  );
 77	
 78	  const udnName = React.useCallback(
 79	    (d: NodeData) => {
 80	      if (!d.peer.udn) {
 81	        return <></>;
 82	      }
 83	      const fields = createPeer({ udn: d.peer.udn });
 84	      const isFiltered = isElementFiltered(fields, filters.list, filterDefinitions);
 85	      return (
 86	        <TextContent id="udn" className="record-field-container">
 87	          <Text component={TextVariants.h4}>{t('UDN')}</Text>
 88	          <Flex>
 89	            <FlexItem flex={{ default: 'flex_1' }}>{d.peer.udn}</FlexItem>
 90	            <FlexItem>
 91	              <Button
 92	                id={'udn-filter'}
 93	                variant="plain"
 94	                className="overflow-button"
 95	                icon={isFiltered ? <TimesIcon /> : <FilterIcon />}
 96	                onClick={() => toggleElementFilter(fields, isFiltered, filters.list, setFilters, filterDefinitions)}
 97	              />
 98	            </FlexItem>
 99	          </Flex>
100	        </TextContent>
101	      );
102	    },
103	    [filterDefinitions, filters, setFilters, t]
104	  );
105	
106	  const metricsInfo = React.useCallback(
107	    (d: NodeData) => {
108	      if (!d.noMetrics) {
109	        return <></>;
110	      }
111	
112	      return (
113	        <TextContent id="noMetrics" className="record-field-container">
114	          <Text component={TextVariants.p}>
115	            {t(
116	              "Can't find metrics for this element. Check your capture filters to ensure we can monitor it. Else it probably means there is no traffic here."
117	            )}
118	          </Text>
119	        </TextContent>
120	      );
121	    },
122	    [t]
123	  );
124	
125	  if (element instanceof BaseNode && data) {
126	    return (
127	      <>
128	        {clusterName(data)}
129	        {udnName(data)}
130	        <ElementFields
131	          id="node-info"
132	          data={data}
133	          forceFirstAsText={true}
134	          filters={filters}
135	          setFilters={setFilters}
136	          filterDefinitions={filterDefinitions}
137	        />
138	        {metricsInfo(data)}
139	      </>
140	    );
141	  } else if (element instanceof BaseEdge) {
142	    // Edge A to B (prefering neutral naming here as there is no assumption about what is source, what is destination
143	    const aData: NodeData = element.getSource().getData();
144	    const bData: NodeData = element.getTarget().getData();
145	    const combinedData = Object.assign({}, aData, bData);
146	    return (
147	      <>
148	        {clusterName(combinedData)}
149	        {udnName(combinedData)}
150	        <Accordion asDefinitionList={false}>
151	          <div className="record-group-container" key={'source'} data-test-id={'source'}>
152	            <AccordionItem data-test-id={'source'}>
153	              <AccordionToggle
154	                className="borderless-accordion"
155	                onClick={() => toggle('source')}
156	                id={'source'}
157	
158	              >
159	                {filters.match === 'bidirectional' ? t('Endpoint A') : t('Source')}
160	              </AccordionToggle>
161	              <AccordionContent
162	                className="borderless-accordion"
163	                id="source-content"
164	
165	              >
166	                <ElementFields
167	                  id="source-info"
168	                  data={aData}
169	                  filters={filters}
170	                  setFilters={setFilters}
171	                  filterDefinitions={filterDefinitions}
172	                />
173	              </AccordionContent>
174	            </AccordionItem>
175	          </div>
176	          <div className="record-group-container" key={'destination'} data-test-id={'destination'}>
177	            <Divider />
178	            <AccordionItem data-test-id={'destination'}>
179	              <AccordionToggle
180	                className="borderless-accordion"
181	                onClick={() => toggle('destination')}
182	                id={'destination'}
183	
184	              >
185	                {filters.match === 'bidirectional' ? t('Endpoint B') : t('Destination')}
186	              </AccordionToggle>
187	              <AccordionContent
188	                className="borderless-accordion"
189	                id="destination-content"
190	
191	              >
192	                <ElementFields
193	                  id="destination-info"
194	                  data={bData}
195	                  filters={filters}
196	                  setFilters={setFilters}
197	                  filterDefinitions={filterDefinitions}
198	                />
199	              </AccordionContent>
200	            </AccordionItem>
201	          </div>
202	        </Accordion>
203	      </>
204	    );
205	  }
206	  return <></>;
207	};
208	
209	export default ElementPanelContent;

